name = "InverseLerp"
inputs = {"a":"float","b":"float","value":"float"}
outputs = {"alpha":"float"}
def process(a, b, value):
    # Inverse linear interpolation - find alpha for a value between a and b
    # Returns 0 when value = a, returns 1 when value = b
    a_val = a if a is not None else 0.0
    b_val = b if b is not None else 1.0
    v = value if value is not None else 0.0
    if abs(b_val - a_val) < 0.0001:
        return 0.0
    alpha = (v - a_val) / (b_val - a_val)
    return max(0.0, min(1.0, alpha))  # Clamp 0-1
